head.script:
scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.data.getMemInfo("privAdmin");

// 상태코드 상수
scwin.NEW        = "01" // 신규
scwin.PREPARESTS = "00" // 준비
scwin.RESERVESTS = "10" // 보류
scwin.WAITSTS    = "20" // 대기
scwin.DECIDESTS  = "30" // 결정
scwin.DECISIONSTS= "40" // 확정
scwin.COMPLETE   = "50" // 완료

// 지급방법코드 상수
scwin.CASH = "10";        // 현금
scwin.TRANSFER = "20";    // 이체
scwin.DRAFTCHECK = "50"    // 실물어음
scwin.ELECTRONICDRAFT = "40"  // 전자어음
scwin.SETOFF = "80"  // 상계

// 합산분할코드
scwin.EXCHANGE = "T"

scwin.vUserHomeClsCd = $c.data.getMemInfo("userHomeClsCd");// 사용자소속구분코드 
scwin.loginCoCd = $c.data.getMemInfo("coCd");
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.loginCoCd)?'':scwin.loginCoCd; // 소속 자회사
scwin.loginCoClsCd = $c.data.getMemInfo("coClsCd");
scwin.vLoginCoClsCd =$c.gus.cfIsNull(scwin.loginCoClsCd)?'': scwin.loginCoClsCd;  ;//회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.isSubCompany = false;

scwin.sAcctDeptCd = $c.data.getMemInfo("acctDeptCd");
scwin.sAppDeptNm = $c.data.getMemInfo("acctDeptNm");
scwin.g_sCurrDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.isStarted = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 처리)
//-------------------------------------------------------------------------
// hidden
//-------------------------------------------------------------------------
scwin.txtCoClsCd = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	//공통코드 적용
    const codeOptions = [
        { grpCd: "FM017", compID: "gr_paymgnt:payStsCd"},//상태
        { grpCd: "FM018", compID: "gr_paymgnt:payMthdCd"},//지급수단
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function() { 

};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    try {
        //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
        if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
            scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
            scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
        }
        ed_coCd.setValue(scwin.vLoginCoCd);

        scwin.f_PopUpCompanyInfo('T');
    } catch (e) {
       console.log(e);
    }
};    

//-------------------------------------------------------------------------
// 회사코드입력시
//-------------------------------------------------------------------------
scwin.udc_coCd_onblurCodeEvent = function (e) {
    scwin.isStarted = false;
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사코드 찾기버튼 클릭시
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = function (e) {
    scwin.isStarted = false;
    scwin.f_PopUpCompanyInfo('F');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {

    /*
     var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
								,ed_coCd.text, txt_coNm.value
								,pWinCloseTF,null,null,null,null
								,null,null,null,null,null);
    */
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc // 콜백 함수
                        , ed_coCd.getValue()              // 화면에서의 ??? Code Element의 Value
                        , ed_coNm.getValue()              // 화면에서의 ??? Name Element의 Value
                        , pWinCloseTF                     // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 콜백
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        // SET	 
        if(rtnList != null ) { 
            if (rtnList[0] == "N/A") return false;  
                if(ed_coCd.hidVal != rtnList[0] )
                    scwin.f_initObj();
                ed_coCd.setValue(rtnList[0]);	// 코드
                ed_coNm.setValue(rtnList[5]);	// 회사명
                ed_coCd.hidVal = rtnList[0];  // 히든값
                scwin.txtCoClsCd = rtnList[1];	// 회사구분  
        }else{
            ed_coCd.setValue("");	// 코드
            ed_coNm.setValue("");	// 회사명
            ed_coCd.hidVal = ""; 
            scwin.txtCoClsCd ="";	// 회사구분    
        }

        if(scwin.txtCoClsCd > '0')  {  	// 자회사 회계 시스템 
            scwin.isSubCompany = true;
        }else{
            scwin.isSubCompany = false;
        }

        if ( scwin.isStarted == true ) {
            if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
                $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);    
            }else {
                $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company  ]);   
            }

            ed_qryStDt.setValue(scwin.g_sCurrDate.substring(0,6) + "01");
            ed_qryEndDt.setValue(scwin.g_sCurrDate);
            ed_acctDeptCd.setValue(scwin.sAcctDeptCd);
            ed_acctDeptNm.setValue(scwin.sAppDeptNm);
        }

    } catch (e) {
       console.log(e);
    }
};    

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    try{
        ds_payment.removeAll();
        let ret = await $c.gus.cfValidate([ed_coCd]);
        if (!ret) {
            return false;
        }

        let ret2 = await $c.gus.cfValidate([ed_qryStDt,ed_qryEndDt]);
        if (!ret2) {
            return false;
        }

        if (ret && ret2) {
            const params = {
                payMthdCd   : scwin.SETOFF , 
                scClsCd     : "0" , 
                payStsCd    : scwin.DECISIONSTS , 
                coClsCd     : scwin.txtCoClsCd , 
            };
            //데이터셋에 정보설정
            ds_condition.setJSON(params);
            ds_payment.removeAll();
            $c.sbm.execute(sbm_retrievePaymgnt);
        }
   }catch (e){
        console.log("f_Retrieve : " + e);
    }  
};

//-------------------------------------------------------------------------
// 조회결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_retrievePaymgnt_submitdone = async function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        tbx_totalRows.setValue($c.gus.cfInsertComma(ds_payment.getRowCount()));
        if( ds_payment.getRowCount() == 0 ){
            await $c.win.alert("조회된 데이터가 없습니다");
            $c.gus.cfDisableObjects([btn_Cancel]);
        }else{
            ds_payment.sort("payNo", 0);//SortExpr +payNo
            $c.gus.cfEnableObjects([btn_Cancel]);
        }
    } catch (e) {
       console.log("sbm_retrievePaymgnt_submitdone >" + e);
    }
};

//-------------------------------------------------------------------------
// 그리드 셀 클릭
//-------------------------------------------------------------------------
scwin.gr_paymgnt_oncellclick = function (rowIndex, columnIndex, columnId) {
    if(columnId=="paySlipNo" && rowIndex >= 0){
        if ( !(ds_payment.getCellData(rowIndex,"paySlipNo") == null || ds_payment.getCellData(rowIndex,"paySlipNo") == "") )
        {
            $c.gus.cfShowSlipInfo(ds_payment.getCellData(rowIndex, "paySlipNo"));
        }
	}
};
//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code) {
    try{
        if (orgObjCd.getValue() != orgObjCd.hidVal) {
            orgObjNm.setValue("");
        }

        if (orgObjCd.getValue().trim() != "") {
            scwin.f_openPopUp(select_code,orgObjCd,orgObjNm,"T");
        }else{
            if (!orgObjNm == null){
                orgObjNm.setValue("");
            }
            orgObjCd.setValue("");
            orgObjCd.hidVal = "";
        }
    } catch (e) {
       console.log("f_CheckPopUp : " + e);
    }
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:검색->관리부서 , 2:검색->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function (select_code,txtCode,txtName,sFlag) {
    try {
        let code ='';
        let name ='';
        let param ='';

        code = txtCode.getValue();
        name = txtName.getValue();

        if(select_code == '1' ||  select_code == '2'){ //자회사 회계시스템 추가사항 - 부서,거래처 선택시 회사코드 필수( 2016.09.22)
            let ret = await $c.gus.cfValidate([ed_coCd]);

            if (!ret){
                return false;
            }
        }
        switch (select_code) {
            // 관리부서 PopUp 호출
            case '1' :
                param    = ","+ ed_coCd.getValue()+","+scwin.txtCoClsCd; //자회사 회계시스템 추가사항
                //rtnList = cfCommonPopUp(sCmdName,code,name,sFlag,null,null,null,null,param,null,null,null,null,null,null,null,null); // 부서
                udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc // 콜백 함수
                        , code                            // 화면에서의 ??? Code Element의 Value
                        , name                            // 화면에서의 ??? Name Element의 Value
                        , sFlag                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );
                break;
            // 거래처 PopUp 호출	
            case '2' :
                param    = ",,,"+ed_coCd.getValue();	//자회사 회계시스템 추가사항
                //rtnList = cfCommonPopUp(sCmdName,code,name,sFlag,null,null,null,null,param,null,null,null,null,null,"F",null,null); // 거래처
                udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                        , code                            // 화면에서의 ??? Code Element의 Value
                        , name                            // 화면에서의 ??? Name Element의 Value
                        , sFlag                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , 'F'                             // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );     
                break;
        }

    } catch (e) {
       console.log("f_openPopUp : " + e);
    }
};

scwin.f_openPopUpNm = async function (select_code,txtCode,txtName,sFlag) {
    try {
        let code ='';
        let name ='';
        let param ='';

        code = "";
        name = txtName.getValue();

        if(select_code == '1' ||  select_code == '2'){ //자회사 회계시스템 추가사항 - 부서,거래처 선택시 회사코드 필수( 2016.09.21)
            let ret = await $c.gus.cfValidate([ed_coCd]);
            if (!ret){
                return false;
            }
        }

        switch (select_code) {
            // 관리부서 PopUp 호출
            case '1' :
                param    = ","+ ed_coCd.getValue()+","+scwin.txtCoClsCd; //자회사 회계시스템 추가사항
                //rtnList = cfCommonPopUp(sCmdName,code,name,sFlag,null,null,null,null,param,null,null,null,null,null,null,null,null); // 부서
                udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc // 콜백 함수
                        , code                            // 화면에서의 ??? Code Element의 Value
                        , name                            // 화면에서의 ??? Name Element의 Value
                        , sFlag                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );
  			break;
            // 거래처 PopUp 호출	
            case '2' :
                param    = ",,,"+ed_coCd.getValue();	//자회사 회계시스템 추가사항
                //rtnList = cfCommonPopUp(sCmdName,code,name,sFlag,null,null,null,null,param,null,null,null,null,null,"F",null,null); // 거래처
                udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                        , code                            // 화면에서의 ??? Code Element의 Value
                        , name                            // 화면에서의 ??? Name Element의 Value
                        , sFlag                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , 'F'                             // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );     
                break;
        }

    } catch (e) {
       console.log("f_openPopUpNm : " + e);
    }
};

//-------------------------------------------------------------------------
// 거래처 PopUp 콜백
//-------------------------------------------------------------------------
scwin.udc_clntNo_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if (rtnList[0] == "N/A"){
				ed_clntNo.setValue("");
                ed_clntNm.setValue("");
                ed_clntNo.hidVal = "";
				return;
			}
			ed_clntNo.setValue(rtnList[0]);	// 코드값
			ed_clntNm.setValue(rtnList[1]);	// 코드명
            ed_clntNo.hidVal = rtnList[0];	// 코드값
		} else {
			ed_clntNo.setValue("");
			ed_clntNm.setValue("");
            ed_clntNo.hidVal = "";
		}

    } catch (e) {
       console.log(e);
    }
};

//-------------------------------------------------------------------------
// 귀속부서 PopUp 콜백
//-------------------------------------------------------------------------
scwin.udc_acctDeptCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if (rtnList[0] == "N/A"){
				ed_acctDeptCd.setValue("");
                ed_acctDeptNm.setValue("");
                ed_acctDeptCd.hidVal = "";
				return;
			}
			ed_acctDeptCd.setValue(rtnList[0]);	// 코드값
			ed_acctDeptNm.setValue(rtnList[1]);	// 코드명
            ed_acctDeptCd.hidVal = rtnList[0];	// 코드값
		} else {
			ed_acctDeptCd.setValue("");
			ed_acctDeptNm.setValue("");
            ed_acctDeptCd.hidVal = "";
		}

    } catch (e) {
       console.log(e);
    }
};

