scwin.openPopup = async function(data){
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

